import pandas as pd

print("Merging Deep Learning results with Docking energies...")

# 1. Load the Chemprop prediction results
# This file was generated by your 'chemprop predict' command
df_dl = pd.read_csv('screening_results.csv')

# 2. Load the Binding Energy file you just uploaded
df_docking = pd.read_csv('model_01_psef_protein_binding_energy.csv')

# 3. Perform the merge
# We match 'pert_iname' from Chemprop to 'Ligand' from the docking file
df_consensus = pd.merge(
    df_dl,
    df_docking[['Ligand', 'Binding Energy (kcal/mol)']],
    left_on='pert_iname',
    right_on='Ligand',
    how='inner'
)

# 4. Clean up redundant columns
if 'Ligand' in df_consensus.columns:
    df_consensus = df_consensus.drop(columns=['Ligand'])

# 5. Sort the results
# We want the highest probability (activity) first, 
# and for those with similar probabilities, the strongest binding energy (most negative) first.
df_consensus = df_consensus.sort_values(
    by=['activity', 'Binding Energy (kcal/mol)'], 
    ascending=[False, True]
)

# 6. Save the final consensus list
output_file = "final_hit_list.csv"
df_consensus.to_csv(output_file, index=False)

print(f"Successfully merged {len(df_consensus)} compounds!")
print(f"Consensus hit list saved as: {output_file}")

# Display the top 10 candidates
print("\n--- TOP 10 CONSENSUS HITS ---")
print(df_consensus[['pert_iname', 'activity', 'Binding Energy (kcal/mol)']].head(10))